var lamp_name = "Beacon"; // Friendly name
var msgs = [];

function friendlyName(name) {
    return "FGFS " + name.split(" ").map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
}

function topicName(name) {
    return name.replace(/ /g, "-").toLowerCase();
}

var topic_name = topicName(lamp_name);

msgs.push({
    topic: "homeassistant/switch/fgfs-" + topic_name + "/config",
    payload: JSON.stringify({
        name: friendlyName(lamp_name),
        unique_id: "fgfs-" + topic_name,
        command_topic: "fgfs/controls/lighting/" + topic_name,
        state_topic: "fgfs/controls/lighting/" + topic_name,  
        payload_on: "true",
        payload_off: "false",
        state_on: "true",
        state_off: "false",
        icon: "mdi:lighthouse-on"
    }),
    retain: true
});

return [msgs];

