var topic = msg.topic;
var payload = msg.payload;

// Convert payload to 1 or 0
var state = (payload === 'true' || payload === true || payload === 'ON' || payload === 'on') ? 1 : 0;

// Check that topic starts with "fgfs/"
if (!topic.startsWith('fgfs/')) return null;

// Remove "fgfs/" from topic for FlightGear
var fgPath = topic.slice(5); // tar bort de första 5 tecknen "fgfs/"

// Set payload for FlightGear
msg.payload = fgPath + ',' + state + '\n';

return msg;

